const pill = (on: boolean): React.CSSProperties => ({
  border:`2px solid ${on ? C.red : C.border}`,
  background: on ? C.redBg : C.white,
  borderRadius:20, padding:"6px 14px", fontSize:11, fontWeight:800,
  color: on ? C.red : C.txt2, cursor:"pointer", whiteSpace:"nowrap", fontFamily:"inherit",
});

const dot = (cur: boolean, done: boolean): React.CSSProperties => ({
  width: cur ? 20 : 8, height:8, borderRadius: cur ? 4 : 99,
  background: cur ? C.red : done ? C.green : C.border,
  border:"none", cursor:"pointer", padding:0, transition:"all .2s",
});

