// ─── SMALL COMPONENTS ─────────────────────────────────────
function DramaMeter({ level }: { level: number }) {
  return (
    <div style={{ display:"flex", alignItems:"center", gap:8, flex:1, marginLeft:10 }}>
      <span style={{ fontSize:9, fontWeight:900, textTransform:"uppercase", letterSpacing:1, color:C.txt3 }}>Drama</span>
      <div style={{ display:"flex", gap:3, flex:1 }}>
        {[1,2,3,4,5].map(i => (
          <div key={i} style={{ height:5, flex:1, borderRadius:3, background: i<=level ? C.red : C.border }} />
        ))}
      </div>
      <span style={{ fontSize:10, fontWeight:800, color:C.red, minWidth:70, textAlign:"right" }}>{DRAMA_N[level]}</span>
    </div>
  );
}

function ImgBanner({ src, bg, title, sub }: { src:string; bg:string; title:string; sub:string }) {
  return (
    <div style={{ ...IMG_BANNER, background:bg }}>
      <img src={src} alt={title} style={IMG_BANNER_IMG} />
      <div style={IMG_OVERLAY}>
        <div style={{ fontSize:16, fontWeight:900, color:"white" }}>{title}</div>
        <div style={{ fontSize:11, color:"rgba(255,255,255,0.82)", fontWeight:600, marginTop:2 }}>{sub}</div>
      </div>
    </div>
  );
}

function HomeCard({ img, bg, accent, num, title, sub, onClick }: {
  img:string; bg:string; accent:string; num:string; title:string; sub:string; onClick:()=>void;
}) {
  return (
    <button onClick={onClick} style={{
      background:C.white, border:`2px solid ${C.border}`, borderTop:`3px solid ${accent}`,
      borderRadius:18, overflow:"hidden", cursor:"pointer", textAlign:"left",
      fontFamily:"inherit", padding:0, display:"block", width:"100%", transition:"all .18s",
    }}>
      <div style={{ ...HCARD_IMGBOX, background:bg }}>
        <img src={img} alt={title} style={HCARD_IMG} />
      </div>
      <div style={{ padding:"11px 14px 14px" }}>
        <div style={{ fontSize:9, fontWeight:900, letterSpacing:2, textTransform:"uppercase", color:accent, marginBottom:4 }}>{num}</div>
        <div style={{ fontFamily:"Georgia,serif", fontSize:17, color:C.txt, marginBottom:3 }}>{title}</div>
        <div style={{ fontSize:11, color:C.txt2, fontWeight:600 }}>{sub}</div>
      </div>
    </button>
  );
}

