function PhrasesPage() {
  const [idx, setIdx] = useState(0);
  const [show, setShow] = useState(false);
  const [done, setDone] = useState<Set<number>>(new Set());
  const p = PHRASES[idx];

  return (
    <div style={pageWrap}>
      <ImgBanner src={IMG_BARISTA} bg={C.redBg} title="☕ Essential Phrases" sub="Learn the most beautiful Italian expressions" />
      <div style={{ display:"flex", justifyContent:"space-between", marginBottom:6 }}>
        <span style={{ fontSize:12, fontWeight:800, color:C.txt2 }}>{idx+1} of {PHRASES.length}</span>
        <span style={{ fontSize:12, fontWeight:800, color:C.green }}>{done.size} learned ✓</span>
      </div>
      <div style={{ height:6, background:C.border, borderRadius:4, marginBottom:14, overflow:"hidden" }}>
        <div style={{ height:"100%", width:`${Math.round((idx+1)/PHRASES.length*100)}%`, background:C.red, borderRadius:4, transition:"width .4s" }} />
      </div>
      <div style={cardStyle}>
        <div style={cardHead}>
          <span style={tag(C.red, C.redBg)}>{p.cat}</span>
          <DramaMeter level={p.drama} />
        </div>
        <div style={cardBody}>
          <div style={{ fontSize:10, fontWeight:900, letterSpacing:2, textTransform:"uppercase", color:C.txt3, marginBottom:8 }}>English</div>
          <div style={{ fontSize:15, fontWeight:700, color:C.txt, lineHeight:1.6, marginBottom:14 }}>{p.en}</div>
          {!show ? (
            <button style={btnRed} onClick={()=>setShow(true)}>👁 Show Italian</button>
          ) : (
            <>
              <hr style={{ border:"none", borderTop:`2px solid ${C.border}`, margin:"12px 0" }} />
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10 }}>
                <span style={{ fontSize:10, fontWeight:900, letterSpacing:2, textTransform:"uppercase", color:C.txt3 }}>Italiano</span>
                <button style={speakBtn} onClick={()=>speak(p.it)}>▶ Listen</button>
              </div>
              <div style={{ fontFamily:"Georgia,serif", fontStyle:"italic", fontSize:22, color:C.red, lineHeight:1.5, marginBottom:8, fontWeight:700 }}>{p.it}</div>
              <div style={{ borderLeft:`4px solid ${C.green}`, paddingLeft:12, fontSize:12, color:C.txt2, fontStyle:"italic", lineHeight:1.8 }}>{p.tip}</div>
              <div style={{ display:"flex", gap:8, marginTop:14 }}>
                <button style={{ ...btnOutline, flex:1 }} onClick={()=>{ setIdx((idx+1)%PHRASES.length); setShow(false); }}>Skip</button>
                <button style={{ ...btnGreen, flex:2, width:"auto", justifyContent:"center", display:"flex", alignItems:"center", gap:6 }}
                  onClick={()=>{ setDone(d=>new Set([...d,idx])); setIdx((idx+1)%PHRASES.length); setShow(false); }}>✓ Got it!</button>
              </div>
            </>
          )}
        </div>
      </div>
      <div style={{ display:"flex", justifyContent:"center", gap:5, flexWrap:"wrap", marginTop:14 }}>
        {PHRASES.map((_,i) => <button key={i} style={dot(i===idx, done.has(i))} onClick={()=>{ setIdx(i); setShow(false); }} />)}
      </div>
    </div>
  );
}

