function ConversationPage() {
  const [ci, setCi] = useState(0);
  const [rev, setRev] = useState(0);
  const conv = CONVOS[ci];
  return (
    <div style={pageWrap}>
      <ImgBanner src={IMG_CONV} bg={C.blueBg} title={conv.scene} sub={conv.loc} />
      <div style={{ display:"flex", gap:6, overflowX:"auto", paddingBottom:4, marginBottom:14 }}>
        {CONVOS.map((c,i) => <button key={i} style={pill(i===ci)} onClick={()=>{ setCi(i); setRev(0); }}>{c.scene}</button>)}
      </div>
      <div style={{ marginBottom:12 }}>
        {conv.lines.slice(0, rev+1).map((line,i) => (
          <div key={i}>
            <div style={{ fontSize:9, fontWeight:900, letterSpacing:1.5, textTransform:"uppercase", color:C.txt3, marginBottom:3, textAlign:line.r==="you"?"right":"left" }}>{line.r==="you"?"You":"Italiano"}</div>
            <div style={{ display:"flex", justifyContent:line.r==="you"?"flex-end":"flex-start" }}>
              <div style={{
                ...(line.r==="you" ? { background:C.navy, color:"#fff", borderRadius:"18px 18px 4px 18px" } : { background:C.white, border:`2px solid ${C.border}`, borderRadius:"18px 18px 18px 4px" }),
                padding:"11px 14px", maxWidth:"82%", marginBottom:8,
              }}>
                <div style={{ fontFamily:"Georgia,serif", fontStyle:"italic", fontSize:14, color:line.r==="you"?"#fff":C.red, marginBottom:3, lineHeight:1.5 }}>{line.it}</div>
                <div style={{ fontSize:11, color:line.r==="you"?"rgba(255,255,255,.7)":C.txt2 }}>{line.en}</div>
              </div>
            </div>
            <div style={{ textAlign:line.r==="you"?"right":"left", marginBottom:10, marginTop:3 }}>
              <button style={speakBtn} onClick={()=>speak(line.it)}>▶ Listen</button>
            </div>
          </div>
        ))}
      </div>
      {rev < conv.lines.length-1
        ? <button style={btnRed} onClick={()=>setRev(r=>r+1)}>Continue →</button>
        : <button style={{ ...btnOutline, width:"100%", justifyContent:"center" }} onClick={()=>setRev(0)}>↩ Start over</button>
      }
    </div>
  );
}

