function GamePage() {
  const [qi, setQi] = useState(0);
  const [score, setScore] = useState(0);
  const [answered, setAnswered] = useState<boolean|null>(null);
  const [done, setDone] = useState(false);
  const q = GIOCO[qi];

  function answer(val: boolean) {
    if (answered !== null) return;
    if (val === q.a) setScore(s=>s+1);
    setAnswered(val);
  }
  function next() {
    if (qi+1 >= GIOCO.length) { setDone(true); return; }
    setQi(i=>i+1); setAnswered(null);
  }
  function restart() { setQi(0); setScore(0); setAnswered(null); setDone(false); }

  if (done) return (
    <div style={{ ...pageWrap, textAlign:"center" }}>
      <div style={{ background:C.redBg, borderRadius:18, padding:24, marginBottom:14 }}>
        <img src={IMG_GIOCO} style={{ width:200, height:200, objectFit:"contain", margin:"0 auto 14px", display:"block" }} alt="Winner" />
        <div style={{ fontFamily:"Georgia,serif", fontSize:56, color:C.red, lineHeight:1, fontWeight:700 }}>
          {score}<span style={{ fontSize:24, color:C.txt3 }}> / {GIOCO.length}</span>
        </div>
        <div style={{ fontSize:14, fontWeight:700, color:C.txt2, marginTop:8 }}>
          {score>=7?"Bravissimo — you think like an Italian!":score>=5?"Non c'è male — keep learning!":"Riprova — try again!"}
        </div>
      </div>
      <button style={btnRed} onClick={restart}>🔄 Play Again!</button>
    </div>
  );

  return (
    <div style={pageWrap}>
      <ImgBanner src={IMG_GIOCO} bg={C.redBg} title="🏆 The Game" sub="Do you think like a real Italian?" />
      <div style={{ display:"flex", justifyContent:"space-between", marginBottom:6 }}>
        <span style={{ fontSize:12, fontWeight:800, color:C.txt2 }}>Question {qi+1} / {GIOCO.length}</span>
        <span style={{ fontSize:13, fontWeight:900, color:C.green }}>{score} correct</span>
      </div>
      <div style={{ height:6, background:C.border, borderRadius:4, marginBottom:14, overflow:"hidden" }}>
        <div style={{ height:"100%", width:`${Math.round(qi/GIOCO.length*100)}%`, background:C.green, borderRadius:4, transition:"width .4s" }} />
      </div>
      <div style={{ background:C.white, border:`2px solid ${C.border}`, borderRadius:18, padding:18, marginBottom:14 }}>
        <div style={{ fontSize:10, fontWeight:900, letterSpacing:2, textTransform:"uppercase", color:C.txt3, textAlign:"center", marginBottom:8 }}>Would an Italian do this?</div>
        <div style={{ fontFamily:"Georgia,serif", fontStyle:"italic", fontSize:17, color:C.txt, textAlign:"center", padding:"14px 4px", lineHeight:1.6 }}>"{q.q}"</div>
      </div>
      {answered === null ? (
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12 }}>
          <button style={{ background:C.greenBg, border:`2.5px solid ${C.greenLight}`, borderRadius:16, padding:18, color:C.green, fontSize:16, fontWeight:900, cursor:"pointer", fontFamily:"inherit" }} onClick={()=>answer(true)}>Sì ✓</button>
          <button style={{ background:C.redBg, border:`2.5px solid ${C.redLight}`, borderRadius:16, padding:18, color:C.red, fontSize:16, fontWeight:900, cursor:"pointer", fontFamily:"inherit" }} onClick={()=>answer(false)}>No ✗</button>
        </div>
      ) : (
        <div>
          <div style={{ background: answered===q.a ? C.greenBg : C.redBg, border:`2px solid ${answered===q.a ? C.greenLight : C.redLight}`, borderRadius:14, padding:14, marginBottom:10 }}>
            <div style={{ fontWeight:900, fontSize:14, color:answered===q.a?C.green:C.red, marginBottom:5 }}>{answered===q.a?"✓ Esatto! Bravissimo!":"✗ Non esattamente."}</div>
            <div style={{ fontSize:12, color:C.txt2, lineHeight:1.8 }}>{q.ex}</div>
          </div>
          <button style={btnRed} onClick={next}>{qi+1>=GIOCO.length?"See your result →":"Next question →"}</button>
        </div>
      )}
    </div>
  );
}

// ─── NAV ──────────────────────────────────────────────────
const NAV = [
  { id:"home",         label:"Home",         icon:"🏠", section:"learn"   },
  { id:"phrases",      label:"Phrases",      icon:"💬", section:"learn",  num:"01" },
  { id:"grammar",      label:"Grammar",      icon:"📖", section:"learn",  num:"02" },
  { id:"conversation", label:"Chat",         icon:"🗣", section:"learn",  num:"03" },
  { id:"gestures",     label:"Gestures",     icon:"🤌", section:"culture",num:"04" },
  { id:"cultura",      label:"Culture",      icon:"🌍", section:"culture",num:"05" },
  { id:"gioco",        label:"The Game",     icon:"🏆", section:"culture",num:"06" },
];

const PAGE_TITLES: Record<string,string> = {
  home:"Welcome", phrases:"Phrases", grammar:"Grammar",
  conversation:"Conversation", gestures:"Gestures", cultura:"Culture", gioco:"The Game",
};

// ─── APP ──────────────────────────────────────────────────
export default function App() {
  const [page, setPage] = useState("home");

  const pages: Record<string,React.ReactNode> = {
    home:         <HomePage setPage={setPage} />,
    phrases:      <PhrasesPage />,
    grammar:      <GrammarPage />,
    conversation: <ConversationPage />,
    gestures:     <GesturesPage />,
    cultura:      <CulturePage />,
    gioco:        <GamePage />,
  };

  return (
    <div style={{ display:"flex", minHeight:"100vh", fontFamily:"'Nunito',system-ui,sans-serif", background:C.bg, color:C.txt }}>

      {/* Sidebar */}
      <div style={{ width:152, flexShrink:0, background:C.white, borderRight:`2px solid ${C.border}`, display:"flex", flexDirection:"column", position:"sticky", top:0, height:"100vh", overflowY:"auto" }}>
        <div style={{ padding:"16px 12px 14px", borderBottom:`2px solid ${C.border}`, textAlign:"center" }}>
          <div style={{ fontSize:24, marginBottom:5 }}>🇮🇹</div>
          <div style={{ fontFamily:"Georgia,serif", fontStyle:"italic", fontSize:14, color:C.red, lineHeight:1.3, fontWeight:700 }}>La Dolce<br/>Lingua</div>
          <div style={{ fontSize:8, letterSpacing:2, color:C.txt3, textTransform:"uppercase", marginTop:3 }}>Vol. I · 2026</div>
        </div>
        {(["learn","culture"] as const).map(sec => (
          <div key={sec}>
            <div style={{ fontSize:8, fontWeight:900, letterSpacing:2, textTransform:"uppercase", color:C.txt3, padding:"14px 12px 4px" }}>{sec}</div>
            {NAV.filter(n=>n.section===sec).map(n => (
              <button key={n.id} onClick={()=>setPage(n.id)} style={{
                display:"flex", alignItems:"center", gap:8, padding:"10px 12px",
                background: page===n.id ? C.redBg : "none",
                border:"none", borderLeft:`3px solid ${page===n.id ? C.red : "transparent"}`,
                width:"100%", textAlign:"left", cursor:"pointer", fontFamily:"inherit",
                fontSize:11, fontWeight:800, color: page===n.id ? C.red : C.txt2,
              }}>
                <span style={{ fontSize:14, width:15, textAlign:"center", flexShrink:0 }}>{n.icon}</span>
                <span>{n.label}</span>
                {"num" in n && n.num && <span style={{ marginLeft:"auto", fontSize:8, color: page===n.id ? C.redLight : C.border, fontWeight:600 }}>{n.num}</span>}
              </button>
            ))}
          </div>
        ))}
      </div>

      {/* Main */}
      <div style={{ flex:1, minWidth:0, background:C.bg, display:"flex", flexDirection:"column" }}>
        <div style={{ background:C.white, borderBottom:`2px solid ${C.border}`, padding:"11px 20px", display:"flex", alignItems:"center", justifyContent:"space-between", position:"sticky", top:0, zIndex:10 }}>
          <span style={{ fontSize:17, fontWeight:900, color:C.txt, fontFamily:"Georgia,serif", fontStyle:"italic" }}>{PAGE_TITLES[page]}</span>
          <span style={{ fontSize:9, fontWeight:900, letterSpacing:1, textTransform:"uppercase", padding:"4px 12px", borderRadius:20, background:C.redBg, color:C.red }}>🇮🇹 Roma · Milano · Napoli</span>
        </div>
        <div style={{ flex:1, overflowY:"auto" }}>
          {pages[page]}
        </div>
      </div>

    </div>
  );
}
